import{_ as o,o as a,c as t,a2 as r}from"./chunks/framework.IwO0Hdn_.js";const m=JSON.parse('{"title":"[SECURITY] F-05.5 — Tabla Users y Mock de Sesión","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-05.5_usuarios_mock_session.md","filePath":"backlog/F-05.5_usuarios_mock_session.md","lastUpdated":null}'),s={name:"backlog/F-05.5_usuarios_mock_session.md"};function d(c,e,n,i,l,u){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="security-f-05-5-—-tabla-users-y-mock-de-sesion" tabindex="-1">[SECURITY] F-05.5 — Tabla Users y Mock de Sesión <a class="header-anchor" href="#security-f-05-5-—-tabla-users-y-mock-de-sesion" aria-label="Permalink to &quot;[SECURITY] F-05.5 — Tabla Users y Mock de Sesión&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-05 — Infraestructura y Conectividad</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Security</code><strong>Secundaria:</strong> <code>Data</code><strong>Impacta en:</strong> Equipo Fullstack (Livewire + Laravel + Base de Datos)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-00.1_setup_laravel_livewire.html">F-00.1</a></td><td>Base Laravel instalada</td></tr><tr><td><a href="./F-00.2_migraciones_modelos.html">F-00.2</a></td><td>Tabla <code>users</code> definida en las migraciones</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como desarrollador Quiero una tabla <code>users</code> en PostgreSQL y un mecanismo de mock de sesión Para que durante el desarrollo se pueda trabajar con un usuario autenticado sin depender del sistema externo de autenticación, y para que los comentarios puedan atribuirse a un autor</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Migración):</strong> Dado que se ejecuta <code>php artisan migrate</code>, cuando la migración corre, entonces la tabla <code>users</code> existe en PostgreSQL con los campos: <code>id</code>, <code>name</code>, <code>email</code>, <code>external_id</code>, <code>created_at</code>, <code>updated_at</code>.</li><li>[ ] <strong>Escenario 2 (Seeder de usuario mock):</strong> Dado que se ejecuta <code>php artisan db:seed --seeder=UserSeeder</code>, cuando el seeder corre, entonces existe al menos un usuario con <code>id=1</code> y <code>name=&quot;Admin&quot;</code> para usar como mock en desarrollo.</li><li>[ ] <strong>Escenario 3 (Middleware AuthMock):</strong> Dado que <code>APP_ENV=local</code>, cuando cualquier petición llega al panel, entonces el middleware <code>AuthMock</code> hace <code>Auth::loginUsingId(1)</code> automáticamente — sin formulario de login.</li><li>[ ] <strong>Escenario 4 (Atribución de comentarios):</strong> Dado que el usuario autenticado añade un comentario, cuando se persiste, entonces <code>comments.user_id</code> se asigna al ID del usuario en sesión (<code>Auth::id()</code>).</li><li>[ ] <strong>Escenario 5 (Policy de comentarios):</strong> Dado que un usuario intenta editar un comentario de otro usuario, cuando se ejecuta la Livewire Action, entonces <code>CommentPolicy@update</code> deniega la operación y devuelve un error de autorización (HTTP 403).</li><li>[ ] <strong>Requisito Técnico:</strong> <code>App\\Models\\User</code> con relaciones <code>hasMany(ArchivedLog::class, &#39;archived_by_id&#39;)</code> y <code>hasMany(Comment::class)</code>. Middleware <code>App\\Http\\Middleware\\AuthMock</code> registrado condicionalmente en <code>bootstrap/app.php</code> solo si <code>APP_ENV !== &#39;production&#39;</code>. <code>UserSeeder</code> en <code>database/seeders/</code>. <code>CommentPolicy</code> registrada en <code>AuthServiceProvider</code>.</li></ul><hr><p><strong>MoSCoW:</strong> <code>MUST</code><strong>Sprint:</strong> Sprint 0</p><p><strong>Notas:</strong></p><ul><li>En producción, <code>AuthMock</code> NO debe estar activo. El middleware <code>AuthGateway</code> (F-05.3) toma el control y autentica desde el sistema externo.</li><li>La tabla <code>users</code> es minimalista — no incluye contraseña local ya que la auth es externa.</li><li><code>external_id</code> permite mapear el usuario del sistema externo con el registro local si fuera necesario.</li></ul>',16)])])}const g=o(s,[["render",d]]);export{m as __pageData,g as default};
